mapper.select:
SELECT p.* FROM product p
INNER JOIN product_tag_relation ptr ON p.id = ptr.product_id
WHERE ptr.tag_id = #{tagId}

mapper.update:
UPDATE product 
SET stock = stock - #{decrease}
WHERE id = #{id} AND stock >= #{decrease}

mapper.select:
SELECT c.id AS categoryId, c.name AS categoryName, c.parent_id AS parentId, COUNT(p.id) AS productCount, COALESCE(AVG(p.price), 0) AS avgPrice, COALESCE(MIN(p.price), 0) AS minPrice, COALESCE(MAX(p.price), 0) AS maxPrice, COALESCE(SUM(p.stock), 0) AS totalStock, COALESCE(SUM(COALESCE(sales_data.sales, 0)), 0) AS totalSales FROM category c LEFT JOIN product p ON c.id = p.category_id LEFT JOIN ( SELECT oi.product_id, SUM(oi.quantity) AS sales FROM order_item oi INNER JOIN orders o ON oi.order_id = o.id WHERE o.status = 2 GROUP BY oi.product_id ) sales_data ON p.id = sales_data.product_id WHERE c.id IN
#{id}
GROUP BY c.id, c.name, c.parent_id ORDER BY c.id

SELECT JSON_ARRAYAGG( JSON_OBJECT( 'categoryId', c.id, 'categoryName', c.name, 'parentId', c.parent_id, 'productCount', COUNT(p.id), 'avgPrice', COALESCE(AVG(p.price), 0), 'minPrice', COALESCE(MIN(p.price), 0), 'maxPrice', COALESCE(MAX(p.price), 0), 'totalStock', COALESCE(SUM(p.stock), 0), 'totalSales', COALESCE(SUM(COALESCE(sales_data.sales, 0)), 0), 'avgRating', COALESCE(AVG(rating_data.avgRating), 0) ) ) AS categories, COUNT(DISTINCT c.id) AS totalCategories, SUM(COUNT(p.id)) AS totalProducts, COALESCE(AVG(p.price), 0) AS overallAvgPrice, COALESCE(SUM(COALESCE(sales_data.sales, 0)), 0) AS overallTotalSales FROM category c LEFT JOIN product p ON c.id = p.category_id LEFT JOIN ( SELECT oi.product_id, SUM(oi.quantity) AS sales FROM order_item oi INNER JOIN orders o ON oi.order_id = o.id WHERE o.status = 2 GROUP BY oi.product_id ) sales_data ON p.id = sales_data.product_id LEFT JOIN ( SELECT pr.product_id, AVG(pr.rating) AS avgRating FROM product_review pr WHERE pr.status = 1 GROUP BY pr.product_id ) rating_data ON p.id = rating_data.product_id WHERE c.id IN
#{id}
GROUP BY NULL
